import numpy as np

def swish(x: np.ndarray) -> np.ndarray:
    return x * (1.0 / (1.0 + np.exp(-np.clip(x, -500, 500))))

def swiglu_ffn(
    x: np.ndarray,
    W_gate: np.ndarray,
    b_gate: np.ndarray,
    W_value: np.ndarray,
    b_value: np.ndarray,
    W_out: np.ndarray,
    b_out: np.ndarray
) -> np.ndarray:
    gate = x @ W_gate + b_gate    # (..., d_ff)
    value = x @ W_value + b_value  # (..., d_ff)
    h = swish(gate) * value        # element-wise gating
    return h @ W_out + b_out       # (..., d_model)
